var dbString = source;
logger.info("source widget : " + JSON.stringify(source));
var resultArray = [];

if (dbString != null) {
    try {
        var spanishPrefix = "ES_";

        // Extract properties from source
        var displayNameEN = source.Title;
        var displayNameES = source.TitleSpanish;
        var displayNameDynamicEN = source.TitleDynamic;
        var displayNameDynamicES = source.TitleDynamicSpanish;

        var appLibDescriptionEN = source.AppLibDescription;
        var appLibDescriptionES = source.AppLibDescriptionSpanish;
        var appLibDescriptionDynamicEN = source.AppLibDescriptionDynamic;
        var appLibDescriptionDynamicES = source.AppLibDescriptionDynamicSpanish;

        var myAppDescriptionEN = source.MyAppsDescription;
        var myAppDescriptionES = source.MyAppsDescriptionSpanish;
        var myAppDescriptionDynamicEN = source.MyAppsDescriptionDynamic;
        var myAppDescriptionDynamicES = source.MyAppsDescriptionDynamicSpanish;

		var appLibBanner = source.AppLibBanner
		var appLibBannerSpanish = source.AppLibBannerSpanish

		var myAppBanner = source.MyAppsBanner
		var myAppBannerSpanish = source.MyAppsBannerSpanish

        var type = source.Type;
        logger.info("widget type : " + type);
        if (type == 0) {
            // Populate displayNameES if missing
            if (displayNameES == null || displayNameES === "") {
                if (displayNameEN != null && displayNameEN !== "") {
                    displayNameES = spanishPrefix + displayNameEN;
                } else {
                    displayNameES = null;
                }
            }
            // Populate appLibDescriptionES if missing
            if (appLibDescriptionES == null || appLibDescriptionES === "") {
                if (appLibDescriptionEN != null && appLibDescriptionEN !== "") {
                    appLibDescriptionES = spanishPrefix + appLibDescriptionEN;
                } else {
                    appLibDescriptionES = null;
                }
            }
            // Populate myAppsDescriptionES if missing
            if (myAppDescriptionES == null || myAppDescriptionES === "") {
                if (myAppDescriptionEN != null && myAppDescriptionEN !== "") {
                    myAppDescriptionES = spanishPrefix + myAppDescriptionEN;
                } else {
                    myAppDescriptionES = null;
                }
            }
			// Populate AppLibBannerSpanish if missing
            if (appLibBannerSpanish == null || appLibBannerSpanish === "") {
                if (appLibBanner != null && appLibBanner !== "") {
                    appLibBannerSpanish = spanishPrefix + appLibBanner;
                } else {
                    appLibBannerSpanish = null;
                }
            }

		    // Populate MyAppsBannerSpanish if missing
            if (myAppBannerSpanish == null || myAppBannerSpanish === "") {
                if (myAppBanner != null && myAppBanner !== "") {
                    myAppBannerSpanish = spanishPrefix + myAppBanner;
                } else {
                    myAppBannerSpanish = null;
                }
            }

            // Prepare result array
            resultArray = [{
                "title": { "en": displayNameEN, "es": displayNameES },
                "appLibDescription": { "en": appLibDescriptionEN, "es": appLibDescriptionES },
                "myAppsDescription": { "en": myAppDescriptionEN, "es": myAppDescriptionES },
				"appLibBanner": { "en": appLibBanner, "es": appLibBannerSpanish },
				"myAppsBanner": { "en": myAppBanner, "es": myAppBannerSpanish }
            }];

            logger.error("Result array for type 0: " + JSON.stringify(resultArray));
             resultArray;
        } else {
            // Process for type != 0
            logger.error("Processing type 1 or others");

            // Handle displayNameDynamicES
            if (displayNameDynamicES == null || displayNameDynamicES === "") {
                if (displayNameDynamicEN != null && displayNameDynamicEN !== "") {
                    displayNameDynamicES = spanishPrefix + displayNameDynamicEN;
                } else {
                    displayNameDynamicES = null;
                }
            }

            // Handle appLibDescriptionDynamicES
            if (appLibDescriptionDynamicES == null || appLibDescriptionDynamicES === "") {
                if (appLibDescriptionDynamicEN != null && appLibDescriptionDynamicEN !== "") {
                    appLibDescriptionDynamicES = spanishPrefix + appLibDescriptionDynamicEN;
                } else {
                    // Do not assign default if no data
                    appLibDescriptionDynamicES = null;
                }
            }

            // Handle myAppsDescriptionDynamicES
            if (myAppDescriptionDynamicES == null || myAppDescriptionDynamicES === "") {
                if (myAppDescriptionDynamicEN != null && myAppDescriptionDynamicEN !== "") {
                    myAppDescriptionDynamicES = spanishPrefix + myAppDescriptionDynamicEN;
                } else {
                    myAppDescriptionDynamicES = null;
                }
            }

			// Populate AppLibBannerSpanish if missing
            if (appLibBannerSpanish == null || appLibBannerSpanish === "") {
                if (appLibBanner != null && appLibBanner !== "") {
                    appLibBannerSpanish = spanishPrefix + appLibBanner;
                } else {
                    appLibBannerSpanish = null;
                }
            }

		    // Populate MyAppsBannerSpanish if missing
            if (myAppBannerSpanish == null || myAppBannerSpanish === "") {
                if (myAppBanner != null && myAppBanner !== "") {
                    myAppBannerSpanish = spanishPrefix + myAppBanner;
                } else {
                    myAppBannerSpanish = null;
                }
            }


            // Prepare result array
            resultArray = [{
                "title": { "en": displayNameEN, "es": displayNameES },
                "appLibDescription": { "en": appLibDescriptionEN, "es": appLibDescriptionES },
                "myAppsDescription": { "en": myAppDescriptionEN, "es": myAppDescriptionES },
				"appLibBanner": { "en": appLibBanner, "es": appLibBannerSpanish },
				"myAppsBanner": { "en": myAppBanner, "es": myAppBannerSpanish }
            }];

            logger.error("Result array for dynamic type: " + JSON.stringify(resultArray));
             resultArray;
        }
    } catch (error) {
        logger.error("Exception: " + error);
    }
} else {
    logger.error("Source is null");
}

var appLibrarySettings = source;
var resultAppLibrarySettings = null;

if (appLibrarySettings != null) {
  try {
    resultAppLibrarySettings = {
      "enrollmentScope": appLibrarySettings.AppLibEnrollmentScope,
      "associatedAppSystemName": appLibrarySettings.AppLibApplicationName,
      "associatedRoleSystemName": appLibrarySettings.AppLibRoleName,
      "applicationURL": appLibrarySettings.AppLibLaunchApplicationURL,
      "enrollmentContext":appLibrarySettings.GUIDExtract
    };
  } catch (error) {
    logger.error("Error processing appLibrarySettings: " + error);
    resultAppLibrarySettings = null;
  }
} else {
  resultAppLibrarySettings = null;
}
resultAppLibrarySettings;

var myAppsSettings = source;
logger.error("myAppsSettings : "+myAppsSettings);

var resultMyAppsSettings = null;

if (myAppsSettings != null) {
  try {
    var allowManageAccess;
	  logger.error("myAppsSettings.MyAppsApplicationName : "+myAppsSettings.MyAppsApplicationName);
	  if(!myAppsSettings.MyAppsApplicationName == null || !myAppsSettings.MyAppsApplicationName == "" || !myAppsSettings.MyAppsApplicationName == "undefined" || !myAppsSettings.MyAppsApplicationName == undefined){

		  allowManageAccess = true;
	  }else{

        allowManageAccess = false;
      }
	var sourceRoleList = myAppsSettings.AssociatedRoleList
	logger.error("sourceRoleList : "+sourceRoleList);
	var roleArray = [];
	if(!sourceRoleList == null || !sourceRoleList == "" || !sourceRoleList == "undefined"){
		const fixedSource = sourceRoleList.replace(/\\"/g, '"'); 	
		roleArray = JSON.parse(fixedSource); 		
	}else{
		roleArray = null;	
	}
    resultMyAppsSettings = {
      "launchURL": myAppsSettings.MyAppsLaunchApplicationURL,
      "associatedAppSystemName": myAppsSettings.MyAppsApplicationName,
      "associatedRoleSystemName": myAppsSettings.MyAppsRoleName,
      "allowManageAccess": allowManageAccess,
	  "associatedRoleList":roleArray
    };
  } catch (error) {
    logger.error("Error processing myAppsSettings: " + error);
    resultMyAppsSettings = null;
  }
} else {
  resultMyAppsSettings = null;
}
resultMyAppsSettings;

var serviceEndPointName = source.ServiceEndPointName;
var result = {}; 
try {
    var serviceEndPointResponse = openidm.query(
        "managed/alpha_kyid_enrollment_service_endpoint",
        {
            "_queryFilter": 'name eq "' + serviceEndPointName + '"'
        },
        ["_id"]
    );
    if (serviceEndPointResponse.result && serviceEndPointResponse.result.length > 0) {
		var serviceEndPointId = serviceEndPointResponse.result[0]._id;
		var serviceEndPointRef = { "_ref": "managed/alpha_kyid_enrollment_service_endpoint/" + serviceEndPointId };
    } else {
		logger.error("Exception occurred in else " );
    }
} catch (e) {
    logger.error("Exception occurred: " + e);  
}
serviceEndPointRef;
